qry:select.qry:xquery:
		for $r in sql('

SELECT 
COUNT(t0.oi_tarea) as cant1
{%?(#PARAM:@rol='USER')
	 {% ,\'./ROLE/LEGALES_USER\' as POLICY  %}
		{% %}
	%}

FROM 
LEG03_TAREAS as t0
{%?(#PARAM:@rol='USER')
	 {% 
	  ,LEG01_CARPETAS as C
	  %}
		{% %}
	%}		


{%?(#PARAM:@rol='USER')
	 {%
	 JOIN
	 t0.oi_carpeta INNER C.oi_carpeta
	 %}
		{% %}
	%}	 

WHERE
1=1		

{%?(#PARAM:@oi_carpeta!='') {% AND t0.oi_carpeta = {#PARAM:@oi_carpeta} %} {% %} %}
{%?(#PARAM:@d_tarea!='') {% AND CONTAIN(t0.d_tarea, \'{%=#PARAM:@d_tarea%}\') %} {% %} %}
{%?(#PARAM:@f_tarea_d!='') {% AND t0.f_tarea >= {#PARAM:@f_tarea_d} %} {% %} %}
{%?(#PARAM:@f_tarea_h!='') {% AND t0.f_tarea <  {Datetime(Number(Datetime(#PARAM:@f_tarea_h))+1)} %} {% %} %}
{%?(#PARAM:@oi_estado_tarea!='') {% AND t0.oi_estado_tarea = {#PARAM:@oi_estado_tarea} %} {% %} %}
{%?(#PARAM:@oi_tipo_tarea!='') {% AND t0.oi_tipo_tarea = {#PARAM:@oi_tipo_tarea} %} {% %} %}
{%?(#PARAM:@oi_clasif_sujeto!='') {% AND t0.oi_clasif_sujeto = {#PARAM:@oi_clasif_sujeto} %} {% %} %}
{%?(#PARAM:@d_lugar_tarea!='') {% AND CONTAIN(t0.d_lugar_tarea, \'{%=#PARAM:@d_lugar_tarea%}\') %} {% %} %}
{%?(#PARAM:@f_vto_tarea_desde!='') {% AND t0.f_vto_tarea >= {#PARAM:@f_vto_tarea_desde} %} {% %} %}
{%?(#PARAM:@f_vto_tarea_hasta!='') {% AND t0.f_vto_tarea <= {Datetime(Number(Datetime(#PARAM:@f_vto_tarea_hasta))+1)} %} {% %} %}

{%?(#PARAM:@rol='USER')
	 {% 

	  AND C.oi_ubicacion IN (SELECT LEG58_SEGURIDAD.oi_ubicacion 

 												FROM LEG58_SEGURIDAD
  											WHERE LEG58_SEGURIDAD.oi_usuario_sys = \'{%=$proxy/@ETTY%}\')					  
	  %}
		{% %}
	%}		


  ')/ROWS/ROW

		for $r in sql('
MAXSIZE 300 
SELECT 
t0.oi_tarea as oi_tarea
{%?(#PARAM:@rol='USER')
	 {% ,\'./ROLE/LEGALES_USER\' as POLICY  %}
		{% %}
	%}

FROM 
LEG03_TAREAS as t0
{%?(#PARAM:@rol='USER')
	 {% 
	  ,LEG01_CARPETAS as C
	  %}
		{% %}
	%}	

{%?(#PARAM:@rol='USER')
	 {%
	 JOIN
	 t0.oi_carpeta INNER C.oi_carpeta
	 %}
		{% %}
	%}	 			

WHERE
1=1
{%?(#PARAM:@oi_carpeta!='') {% AND t0.oi_carpeta = {#PARAM:@oi_carpeta} %} {% %} %}
{%?(#PARAM:@d_tarea!='') {% AND CONTAIN(t0.d_tarea, \'{%=#PARAM:@d_tarea%}\') %} {% %} %}
{%?(#PARAM:@f_tarea_d!='') {% AND t0.f_tarea >= {#PARAM:@f_tarea_d} %} {% %} %}
{%?(#PARAM:@f_tarea_h!='') {% AND t0.f_tarea <  {Datetime(Number(Datetime(#PARAM:@f_tarea_h))+1)} %} {% %} %}
{%?(#PARAM:@oi_estado_tarea!='') {% AND t0.oi_estado_tarea = {#PARAM:@oi_estado_tarea} %} {% %} %}
{%?(#PARAM:@oi_tipo_tarea!='') {% AND t0.oi_tipo_tarea = {#PARAM:@oi_tipo_tarea} %} {% %} %}
{%?(#PARAM:@oi_clasif_sujeto!='') {% AND t0.oi_clasif_sujeto = {#PARAM:@oi_clasif_sujeto} %} {% %} %}
{%?(#PARAM:@d_lugar_tarea!='') {% AND CONTAIN(t0.d_lugar_tarea, \'{%=#PARAM:@d_lugar_tarea%}\') %} {% %} %}
{%?(#PARAM:@f_vto_tarea_desde!='') {% AND t0.f_vto_tarea >= {#PARAM:@f_vto_tarea_desde} %} {% %} %}
{%?(#PARAM:@f_vto_tarea_hasta!='') {% AND t0.f_vto_tarea <= {Datetime(Number(Datetime(#PARAM:@f_vto_tarea_hasta))+1)} %} {% %} %}

{%?(#PARAM:@rol='USER')
	 {% 

	  AND C.oi_ubicacion IN (SELECT LEG58_SEGURIDAD.oi_ubicacion 

 												FROM LEG58_SEGURIDAD
  											WHERE LEG58_SEGURIDAD.oi_usuario_sys = \'{%=$proxy/@ETTY%}\')					  
	  %}
		{% %}
	%}		


ORDER BY 
oi_tarea asc')/ROWS/ROW
